import logging
import azure.functions as func
from azure.storage.blob import BlobServiceClient
from azure.identity import DefaultAzureCredential

def main(req: func.HttpRequest) -> func.HttpResponse:
    logging.info('Python HTTP trigger function processed a request.')

    try:
        blob_path = req.params.get('blobPath')
        
        if not blob_path:
            return func.HttpResponse(
                "Please pass the blob path on the query string or in the request body.",
                status_code=400
            )

        credential = DefaultAzureCredential()
        blob_service_client = BlobServiceClient.from_connection_string(
            credential,
            account_url="https://your_storage_account_name.blob.core.windows.net"
        )
        
        container_name, blob_name = blob_path.split('/')
        
        blob_client = blob_service_client.get_blob_client(container=container_name, blob=blob_name)
        
        with open(blob_name, "wb") as file:
            data = blob_client.download_blob().content_as_bytes()
            file.write(data)

        return func.HttpResponse(
            f"Blob {blob_path} downloaded successfully.",
            status_code=200
        )

    except Exception as e:
        logging.info(f'An error occurred: {e}')
        return func.HttpResponse(
            "An error occurred. Please try again later.",
            status_code=500
        )